import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const root = path.join(path.dirname(fileURLToPath(import.meta.url)), '..')
const sortsDir = path.join(root, 'src/workers/sorts')
const outFile = path.join(root, 'src/components/SourceCodePreview/sourceMap.generated.ts')

const entries = [
  ['BubbleSort', 'bubble.sort.ts'],
  ['InsertionSort', 'insertion.sort.ts'],
  ['MergeSort', 'merge.recursive.sort.ts'],
  ['QuickSort', 'quick.sort.ts'],
  ['CocktailShakerSort', 'cocktailShakerSort.sort.ts'],
]

const lines = [
  '// This file is auto-generated by scripts/embed-sort-sources.mjs',
  '',
  'export const sourceMap: Record<string, string> = {',
]

for (const [key, file] of entries) {
  const content = fs.readFileSync(path.join(sortsDir, file), 'utf8')
  lines.push(`  ${key}: ${JSON.stringify(content)},`)
}

lines.push('}', '')

fs.writeFileSync(outFile, lines.join('\n'))
console.log(`Generated ${path.relative(root, outFile)}`)
